42	/**
43	 * Creates a schema with deferred creation.
44	 * This is important to reduce the startup time of the library
45	 * and to avoid initializing unused validators.
46	 *
47	 * @param createValidator A function that creates a schema.
48	 * @returns A function that returns a schema.
49	 */
50	export function lazySchema<SCHEMA>(
51	  createSchema: () => Schema<SCHEMA>,
52	): LazySchema<SCHEMA> {
53	  // cache the validator to avoid initializing it multiple times
54	  let schema: Schema<SCHEMA> | undefined;
55	  return () => {
56	    if (schema == null) {
57	      schema = createSchema();
58	    }
59	    return schema;
60	  };
61	}
62	
63	export type LazySchema<SCHEMA> = () => Schema<SCHEMA>;
64	
65	export type ZodSchema<SCHEMA = any> =
66	  | z3.Schema<SCHEMA, z3.ZodTypeDef, any>
67	  | z4.core.$ZodType<SCHEMA, any>;
68	
69	export type StandardSchema<SCHEMA = any> = StandardSchemaV1<unknown, SCHEMA> &
70	  StandardJSONSchemaV1<unknown, SCHEMA>;
71	
72	export type FlexibleSchema<SCHEMA = any> =
73	  | Schema<SCHEMA>
74	  | LazySchema<SCHEMA>
75	  | ZodSchema<SCHEMA>
76	  | StandardSchema<SCHEMA>;
77	
78	export type InferSchema<SCHEMA> =
79	  SCHEMA extends ZodSchema<infer T>
80	    ? T
81	    : SCHEMA extends StandardSchema<infer T>
82	      ? T
83	      : SCHEMA extends LazySchema<infer T>
84	        ? T
85	        : SCHEMA extends Schema<infer T>
86	          ? T
87	          : never;
