173	export function zod3Schema<OBJECT>(
174	  zodSchema: z3.Schema<OBJECT, z3.ZodTypeDef, any>,
175	  options?: {
176	    /**
177	     * Enables support for references in the schema.
178	     * This is required for recursive schemas, e.g. with `z.lazy`.
179	     * However, not all language models and providers support such references.
180	     * Defaults to `false`.
181	     */
182	    useReferences?: boolean;
