208	    /**
209	     * Enables support for references in the schema.
210	     * This is required for recursive schemas, e.g. with `z.lazy`.
211	     * However, not all language models and providers support such references.
212	     * Defaults to `false`.
213	     */
214	    useReferences?: boolean;
