140	    const {
141	      value: { output },
142	      responseHeaders,
143	    } = await postJsonToApi({
144	      url:
145	        // different endpoints for versioned vs unversioned models:
146	        version != null
147	          ? `${this.config.baseURL}/predictions`
148	          : `${this.config.baseURL}/models/${modelId}/predictions`,
149	
150	      headers: combineHeaders(
151	        await resolve(this.config.headers),
152	        headers,
153	        preferHeader,
154	      ),
155	
156	      body: {
157	        input: {
158	          prompt,
159	          aspect_ratio: aspectRatio,
160	          size,
161	          seed,
162	          num_outputs: n,
