4	const FETCH_FAILED_ERROR_MESSAGES = ['fetch failed', 'failed to fetch'];
5	
6	const BUN_ERROR_CODES = [
7	  'ConnectionRefused',
8	  'ConnectionClosed',
9	  'FailedToOpenSocket',
10	  'ECONNRESET',
11	  'ECONNREFUSED',
12	  'ETIMEDOUT',
13	  'EPIPE',
14	];
15	
16	function isBunNetworkError(error: unknown): error is Error & { code?: string } {
17	  if (!(error instanceof Error)) {
18	    return false;
19	  }
20	
21	  const code = (error as any).code;
22	  if (typeof code === 'string' && BUN_ERROR_CODES.includes(code)) {
23	    return true;
24	  }
25	
26	  return false;
27	}
