**Factory Function Pattern:**
```typescript
export function create<ProviderName>(options: Settings = {}): Provider {
  // 1. Resolve baseURL with environment variable fallback
  const baseURL = withoutTrailingSlash(
    loadOptionalSetting({
      settingValue: options.baseURL,
      environmentVariableName: '<PROVIDER>_BASE_URL'
    })
  ) ?? 'https://default.api.com/v1';

  // 2. Set provider name
  const providerName = options.name ?? 'provider.default';

  // 3. Create getHeaders function (memoized, called at request time)
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({...})}`,
        ...options.headers
      },
      `ai-sdk/<provider>/${VERSION}`
    );

  // 4. Create factory functions for each model type
  const createChatModel = (modelId) => new ChatLanguageModel(modelId, {...});
  const createEmbeddingModel = (modelId) => new EmbeddingModel(modelId, {...});
  // ... etc

  // 5. Create provider object (callable function with attached methods)
  const provider = function (modelId) {
    if (new.target) throw new Error('Cannot be called with new keyword');
    return createChatModel(modelId);
  };

  // 6. Attach specification and methods
  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createChatModel;
  provider.chat = createChatModel;
  provider.embedding = createEmbeddingModel;
  provider.embeddingModel = createEmbeddingModel;
  provider.tools = <providerName>Tools;

  return provider as Provider;
}

// 7. Export default instance
export const <providerName> = create<ProviderName>();
```

