From OpenAI's ImageModel implementation (`/packages/openai/src/image/openai-image-model.ts`):

```typescript
import { ImageModelV3, ImageModelV3File, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  convertToFormData,
  createJsonResponseHandler,
  postFormDataToApi,
  postJsonToApi,
} from '@ai-sdk/provider-utils';

export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  constructor(readonly modelId: string, private readonly config: OpenAIConfig) {}

  get provider(): string { return this.config.provider; }
  get maxImagesPerCall(): number { return 1; }

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    // Load provider options
    const openaiOptions = await parseProviderOptions({
      provider: this.provider,
      providerOptions: options.providerOptions,
      schema: openaiImageOptionsSchema,
    });

    // Make API call with proper handlers
    const { value: response } = await postJsonToApi({
      url: this.config.url({ path: '/images/generations' }),
      headers: combineHeaders(...),
      body: { prompt: options.prompt, n: options.n, ... },
      failedResponseHandler: openaiFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(openaiImageResponseSchema),
      abortSignal: options.abortSignal,
    });

    return {
      images: response.data.map(img => img.b64_json),
      warnings,
      response: { timestamp: new Date(), modelId: this.modelId, headers: ... }
    };
  }
}
```

