174	  model: string;
175	  prompt: string | undefined;
176	  image: Blob | Blob[];
177	  mask?: Blob;
178	  n: number;
179	  size: `${number}x${number}` | undefined;
180	  [key: string]: unknown;
181	};
182	
183	async function fileToBlob(file: ImageModelV3File): Promise<Blob> {
184	  if (file.type === 'url') {
185	    return downloadBlob(file.url);
186	  }
187	
188	  const data =
189	    file.data instanceof Uint8Array
190	      ? file.data
191	      : convertBase64ToUint8Array(file.data);
192	
193	  return new Blob([data as BlobPart], { type: file.mediaType });
194	}
